events.success:
function successCallback(res) {
    if (res.data) {
        $this.utils.notification.success({
            title: '成功',
            content: '更新用户成功',
        });
        $this.parent.datasourceMap.getUserData()
		$this.close();
    } else {
        $this.utils.notification.error({
            title: '失败',
            content: '更新用户失败',
        })
    }
}

events.fail:
function failCallback() {
    $this.utils.notification.error({
        title: '失败',
        content: '更新用户失败',
    })
}

